package main.rice.node;

import main.rice.obj.APyObj;

import java.util.List;
import java.util.Random;
import java.util.Set;

/**
 * Abstract class representing a node in the type tree for generating Python objects.
 *
 * @param <T> the type of elements in the domain (e.g., Integer, Double)
 * @param <E> the type of PyObj produced by this node
 */
public abstract class APyNode<T, E extends APyObj> {

    protected static final Random rand = new Random();

    protected List<T> exDomain;
    protected List<T> ranDomain;

    public void setExDomain(List<T> domain) {
        this.exDomain = domain;
    }

    public List<T> getExDomain() {
        return this.exDomain;
    }

    public void setRanDomain(List<T> domain) {
        this.ranDomain = domain;
    }

    public List<T> getRanDomain() {
        return this.ranDomain;
    }

    public abstract APyNode<?, ?> getLeftChild();

    public abstract APyNode<?, ?> getRightChild();

    public abstract Set<E> genExVals();

    public abstract E genRandVal();
}

package main.rice.node;

import main.rice.obj.PyBoolObj;

import java.util.HashSet;
import java.util.Set;

/**
 * A node that generates Python boolean values (True/False).
 * The domain consists of integers: 0 represents False, 1 represents True.
 */
public class PyBoolNode extends APyNode<Integer, PyBoolObj> {

    @Override
    public APyNode<?, ?> getLeftChild() {
        return null;
    }

    @Override
    public APyNode<?, ?> getRightChild() {
        return null;
    }

    @Override
    public Set<PyBoolObj> genExVals() {
        Set<PyBoolObj> result = new HashSet<>();
        for (Integer val : this.exDomain) {
            if (val == 0) {
                result.add(new PyBoolObj(false));
            } else if (val == 1) {
                result.add(new PyBoolObj(true));
            }
        }
        return result;
    }

    @Override
    public PyBoolObj genRandVal() {
        int idx = rand.nextInt(this.ranDomain.size());
        int val = this.ranDomain.get(idx);
        return new PyBoolObj(val == 1);
    }
}

