package main.rice.concisegen;

import main.rice.test.TestCase;
import main.rice.test.TestResults;

import java.util.HashSet;
import java.util.List;
import java.util.Set;

/**
 * Generates a minimal (concise) set of test cases that covers all buggy implementations,
 * using a greedy set cover algorithm.
 */
public class ConciseSetGenerator {

    /**
     * Returns a minimal set of test cases that covers all files in the wrong set.
     * Uses a greedy algorithm: at each step, picks the test case that covers the
     * most currently uncovered files.
     *
     * Does NOT mutate the input TestResults object.
     *
     * @param results the test results containing all cases, coverage info, and wrong set
     * @return a minimal covering set of test cases
     */
    public static Set<TestCase> setCover(TestResults results) {
        // Work with a copy of the wrong set to avoid mutation
        Set<Integer> uncovered = new HashSet<>(results.getWrongSet());
        List<Set<Integer>> caseToFiles = results.getCaseToFiles();
        Set<TestCase> cover = new HashSet<>();

        while (!uncovered.isEmpty()) {
            int bestIdx = -1;
            int bestCount = -1;

            // Find the test case that covers the most uncovered files
            // (iterate in order for deterministic tie-breaking)
            for (int i = 0; i < caseToFiles.size(); i++) {
                // Count how many uncovered files this test case covers
                int count = 0;
                for (Integer file : caseToFiles.get(i)) {
                    if (uncovered.contains(file)) {
                        count++;
                    }
                }
                if (count > bestCount) {
                    bestCount = count;
                    bestIdx = i;
                }
            }

            if (bestIdx == -1 || bestCount == 0) {
                break;
            }

            // Add the best test case to the cover
            cover.add(results.getTestCase(bestIdx));

            // Remove all files covered by this test case from uncovered
            for (Integer file : caseToFiles.get(bestIdx)) {
                uncovered.remove(file);
            }
        }

        return cover;
    }
}
